        setTimeout(function() {
          var script = document.createElement('script');
          script.id = 'Cookiebot';
          script.src = 'https://consent.cookiebot.com/uc.js';
          script.setAttribute('data-cbid', 'd5c4a99d-97d6-45b8-b9c1-8812f8c9a1a2');
          script.type = 'text/javascript';
          document.head.appendChild(script);

          script.onload = function() {
            var defaultScript = document.createElement('script');
            defaultScript.src = 'https://culqi.com/assets/js/cookiebot/default.js';
            document.head.appendChild(defaultScript);
          };
        }, 2000);
      });

