div.script:
const sidebarMenu = document.querySelector('#mobile_menu_sidebar');
  const menuBtn = document.querySelector('#btn_menu');

  const sidebarTriggers = [menuBtn, document.querySelector('#mobile_sidebar_layer')]

  sidebarTriggers.forEach(trigger => {
    trigger.addEventListener('click', function(e){
      if (e.target.id !== trigger.id) return;
      menuBtn?.classList.toggle('active');
      sidebarMenu?.classList.toggle('active');
    });
  });

body.script:
document.addEventListener('DOMContentLoaded', () => {
		const removeClass = (name, query) => {
			if (document.querySelector(`${name}.${query}`)) {
				document.querySelector(`${name}.${query}`).classList.remove(query)
			}
		}

		const closeDropdown = () => {
			removeClass('#desktop-navbar .withSubNavbar', 'active');
			removeClass('.navbar_actions .withSubNavbar', 'active');
			removeClass('.navbar_sub', 'active');
		}

		const dropdownMenu = document.querySelectorAll('.withSubNavbar');
		const navbarSub = document.querySelector('.navbar_sub');

		window.addEventListener("click", function (e) {
			// console.log(e.target.closets('.navbar_sub'));
			if (!e.target.classList.contains('withSubNavbar') && !e.target.closest('.navbar_sub')) {
				closeDropdown();
			}
		});


		Array.from(dropdownMenu).forEach((item) => {
			item.addEventListener('click', function (e) {
				if (this.nextElementSibling.classList.contains('active')) {
					this.classList.remove("active");
					this.nextElementSibling.classList.remove("active");
				} else {
					closeDropdown()
					this.classList.add("active");
					this.nextElementSibling.classList.add("active");
				}
			})
		})
		// tab


	});

/*  Tabs  rubrosSwiper */
(function () {
  'use strict';

  function getRubrosSwiper() {
    try {
      return (window && window.mySwipers && window.mySwipers['rubrosSwiper']) || null;
    } catch (e) { return null; }
  }

  function attachRubrosBehavior(swiper) {
    if (!swiper || typeof swiper.slideTo !== 'function') return;

    var container = document.querySelector('.rubros');
    if (!container) return;

    var tabs  = Array.prototype.slice.call(container.querySelectorAll('.rubro-tab'));
    var names = Array.prototype.slice.call(container.querySelectorAll('.rubro-name'));
    if (!tabs.length) return;

    function syncTabs(realIndex) {
      for (var i = 0; i < tabs.length; i++) {
        var isActive = i === realIndex;
        var tab = tabs[i];
        if (isActive) {
          tab.classList.add('active');
          tab.setAttribute('aria-selected', 'true');
          tab.setAttribute('tabindex', '0');
          if (names[i]) names[i].classList.add('active');
        } else {
          tab.classList.remove('active');
          tab.setAttribute('aria-selected', 'false');
          tab.setAttribute('tabindex', '-1');
          if (names[i]) names[i].classList.remove('active');
        }
      }
    }

    try { syncTabs(swiper.realIndex || 0); } catch (e) {}
    if (typeof swiper.on === 'function') {
      swiper.on('slideChange', function () {
        try { syncTabs(swiper.realIndex || 0); } catch (e) {}
      });
    }

    for (var t = 0; t < tabs.length; t++) {
      tabs[t].addEventListener('click', function () {
        try {
          var idx = Number(this.getAttribute('data-rubro-index')) || 0;
          swiper.slideTo(idx);
        } catch (e) {}
      });
    }

    var tablist = container.querySelector('.rubros-tabs[role="tablist"]');
    if (tablist) {
      tablist.addEventListener('keydown', function (ev) {
        var key = ev.key || ev.code;
        if (!key) return;

        var currentIndex = 0;
        for (var i = 0; i < tabs.length; i++) {
          if (tabs[i].classList.contains('active')) { currentIndex = i; break; }
        }

        if (key === 'ArrowRight' || key === 'Right') {
          ev.preventDefault();
          var next = (currentIndex + 1) % tabs.length;
          tabs[next].focus();
          tabs[next].click();
        } else if (key === 'ArrowLeft' || key === 'Left') {
          ev.preventDefault();
          var prev = (currentIndex - 1 + tabs.length) % tabs.length;
          tabs[prev].focus();
          tabs[prev].click();
        }
      });
    }
  }

  function initRubrosHook() {
    var instance = getRubrosSwiper();
    if (instance) {
      attachRubrosBehavior(instance);
      return true;
    }
    return false;
  }

  if (!initRubrosHook()) {
    window.addEventListener('load', initRubrosHook, { once: true });
  }
})();

