section.script:
(function () {
            function init() {
                if (!window.Swiper) { return setTimeout(init, 50); }

                const root = document.getElementById('beneficios');

                const swiperEl = root.querySelector('[data-benefits-swiper]');
                const pagEl = root.querySelector('[data-benefits-pagination]');
                const prevEl = root.querySelector('[data-benefits-prev]');
                const nextEl = root.querySelector('[data-benefits-next]');
                const toggleBtn = root.querySelector('[data-benefits-toggle]');

                const isMobile = window.innerWidth < 768;
                let swiperInstance = null;

                function initOrDestroySwiper() {
                    const nowMobile = window.innerWidth < 768;

                    if (nowMobile && !swiperInstance) {
                        swiperInstance = new Swiper(swiperEl, {
                            slidesPerView: 1,
                            spaceBetween: 400,
                            centeredSlides: true,
                            loop: true,
                            watchOverflow: false,
                            roundLengths: true,
                            navigation: { prevEl, nextEl },
                            pagination: { el: pagEl, clickable: true },
                        });

                    } else if (!nowMobile && swiperInstance) {
                        swiperInstance.destroy(true, true);
                        swiperInstance = null;
                    }
                }

                initOrDestroySwiper();
                window.addEventListener('resize', initOrDestroySwiper);

                if (toggleBtn) {
                    toggleBtn.addEventListener('click', function () {
                        root.classList.toggle('is-open');
                        const open = root.classList.contains('is-open');
                        toggleBtn.textContent = open ? 'Ver menos' : 'Ver más beneficios';
                    });
                }
            }

            if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
            else init();
        })();

