const navDataTabHeader2 = document.querySelectorAll('[data-tab-header2]');
  const navDataTabBody2 = document.querySelectorAll('[data-tab-body2]');
  // console.log(navDataTab);
  Array.from(navDataTabHeader2).map(function (e, i, a) {
    e.addEventListener('click', function () {
      const attr = this.getAttribute('data-tab-header2');
      Array.from(navDataTabHeader2).map(function (e, i, a) {
        e.classList.remove('active');
      });

      Array.from(navDataTabBody2).map(function (e, i, a) {
        e.classList.remove('active');
      });

      e.classList.add('active');
      document.querySelector('[data-tab-body2=' + attr + ']').classList.add('active');
    });
  });

