(function () {
    try {
      var f = document.createElement('iframe');
      f.src =
        'https://forms.zohopublic.com/culqiperu/form/Djanostusdatosytecontactaremos2/formperma/7NiQOZ2X7hDw5vRLF8dvBlyaiZQpgFwUQlguJLjk1jU?zf_rszfm=1&referrername=culqi.com';
      f.style.border = 'none';
      f.style.width = '99%';
      f.style.transition = 'all 0.5s ease';
      f.setAttribute('aria-label', '\xBFNecesitas\x20ayuda\x3F');
      f.setAttribute('scrolling', 'yes');

      // Ajustar la altura del iframe dinámicamente en móviles
      function ajustarAltura() {
        if (window.innerWidth <= 768) {
          f.style.height = window.innerHeight + 'px';
          f.style.height = '1200px';
          f.style.overflowY = 'auto';
        } else {
          f.style.height = '1200px';
          f.style.overflow = 'hidden';
        }
      }

      window.addEventListener('resize', ajustarAltura);
      ajustarAltura();

      var d = document.getElementById(
        'zf_div_7NiQOZ2X7hDw5vRLF8dvBlyaiZQpgFwUQlguJLjk1jU',
      );
      d.appendChild(f);
      window.addEventListener(
        'message',
        function () {
          var evntData = event.data;
          if (evntData && evntData.constructor == String) {
            var zf_ifrm_data = evntData.split('|');
            if (zf_ifrm_data.length == 2 || zf_ifrm_data.length == 3) {
              var zf_perma = zf_ifrm_data[0];
              var zf_ifrm_ht_nw = parseInt(zf_ifrm_data[1], 10) + 15 + 'px';
              var iframe = document
                .getElementById(
                  'zf_div_7NiQOZ2X7hDw5vRLF8dvBlyaiZQpgFwUQlguJLjk1jU',
                )
                .getElementsByTagName('iframe')[0];
              if (
                iframe.src.indexOf('formperma') > 0 &&
                iframe.src.indexOf(zf_perma) > 0
              ) {
                var prevIframeHeight = iframe.style.height;
                var zf_tout = false;
                if (zf_ifrm_data.length == 3) {
                  iframe.scrollIntoView();
                  zf_tout = true;
                }
                if (prevIframeHeight != zf_ifrm_ht_nw) {
                  if (zf_tout) {
                    setTimeout(function () {
                      iframe.style.height = zf_ifrm_ht_nw;
                    }, 500);
                  } else {
                    iframe.style.height = zf_ifrm_ht_nw;
                  }
                }
              }
            }
          }
        },
        false,
      );
    } catch (e) {}
  })();

const tarifarioLayer = document.getElementById("tarifario-layer");
  const tarifarioTriggers = document.querySelectorAll("[data-open-tarifario]");

  Array.from(tarifarioTriggers).forEach((trigger) => {
    trigger.addEventListener("click", (e) => {
      const type = trigger.dataset.openTarifario;
      displayTarifario(type);
    });
  });

  const displayTarifario = (type) => {
    const tarifario = document.querySelector(`#tarifario-${type}`)
    if (tarifario) {
      tarifario.classList.toggle("active", true);
      tarifarioLayer.classList.toggle("show-tarifario", true);
    }
  };

  document.getElementById("close-tarifario-modal").addEventListener('click', () => {
    tarifarioLayer.classList.remove("show-tarifario");
    setTimeout(() => {
        document
          .querySelector(".tarifario-modal-container.active")
          ?.classList.remove("active");
      }, 300);
  });

const scheduleLayer = document.getElementById("schedule-layer");
  const scheduleTriggers = document.querySelectorAll("[data-open-schedule]");

  Array.from(scheduleTriggers).forEach((trigger) => {
    trigger.addEventListener("click", (e) => {
      const type = trigger.dataset.openSchedule;
      displaySchedule(type);
    });
  });

  const displaySchedule = (type) => {
    const schedule = document.querySelector(`#modal-schedule-${type}`)
    if (schedule) {
      schedule.classList.toggle("active", true);
      scheduleLayer.classList.toggle("show-modal", true);
    }
  };

  document.getElementById("close-schedule-modal").addEventListener('click', () => {
    scheduleLayer.classList.remove("show-modal");
    setTimeout(() => {
        document
          .querySelector(".base-modal-container.active")
          ?.classList.remove("active");
      }, 300);
  });

document.addEventListener("DOMContentLoaded", function () {
    // Toggle Footer Items
    const toggleHeaders = document.querySelectorAll(".footer-toggle-title");

    Array.from(toggleHeaders).forEach((item) => {
      item.addEventListener("click", () => {
        const body = document.getElementById(item.dataset.toggleBody);
        body.classList.toggle("active");
        item.querySelector(".arrow").classList.toggle("active");
      });
    });


    // Modal Libro de Reclamaciones
    const libroReclamacionesModal = document.querySelector(
      '[data-show-modal="libro_reclamaciones"]'
    );

    document
      .querySelector('[data-hide-modal="libro_reclamaciones"]')
      .addEventListener("click", function () {
        libroReclamacionesModal.classList.remove("active");
      });

    document
      .querySelector(".modal__libro-reclamaciones")
      .addEventListener("click", function () {
        libroReclamacionesModal.classList.add("active");
      });
  });

const cookieModalFooter = document.querySelector(
    ".cookies-settings-content__footer"
  );

  // handle Cookie tabs

  const cookieTabs = document.querySelectorAll(
    ".cookies-settings-content__tab"
  );
  const cookieTabContent = document.querySelector(
    ".cookies-settings-content__tab-content"
  );
  const sobreButtons = document.getElementById("sobre-buttons");
  const preferencesButtons = document.getElementById("preferences-buttons");

  Array.from(cookieTabs).forEach((tab) => {
    tab.addEventListener("click", () => {
      document
        .querySelector(".cookies-settings-content__tab.active")
        ?.classList.remove("active");
      document
        .querySelector(".cookies-settings-content__tab-content.active")
        ?.classList.remove("active");

      const contentId = tab.dataset.contentId;

      if (contentId === "cookies_section_preferences") {
        sobreButtons.style.display = "none";
        preferencesButtons.style.display = "flex";
      } else if (contentId === "cookies_section_about") {
          sobreButtons.style.display = "flex";
          preferencesButtons.style.display = "none";
      }

      document.getElementById(contentId).classList.add("active");
      tab.classList.add("active");
    });
  });

  // handle Cookie toogles

  const toggleItems = document.querySelectorAll("input.toggle");

  Array.from(toggleItems).forEach((toggle) => {
    toggle.addEventListener("click", () => {
      const content = document.querySelector(
        `.collapsible-content[data-for=${toggle.id}]`
      );
      if (content) {
        const height = toggle.checked ? "5000px" : 0;
        content.style.maxHeight = height;
      }
    });
  });

window.addEventListener('DOMContentLoaded', () => {
    // handle Calulator Tabs

    const tabCalculatorOptions = {
